"use client";

import * as React from "react";

import { Glass } from "@/components/ui/glass";
import { cn } from "@/lib/utils";

/**
 * The iOS 26 floating Liquid Glass tab bar: a capsule that hovers
 * above content with a brighter glass pill sliding between tabs
 * (glass morphing between positions, per the Liquid Glass spec).
 */
type Item = { value: string; icon?: React.ReactNode; label: React.ReactNode };

function GlassTabBar({
  className,
  items,
  value: valueProp,
  defaultValue,
  onValueChange,
  variant = "regular",
  ...props
}: Omit<React.ComponentProps<"div">, "defaultValue" | "onChange"> & {
  items: Item[];
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
  variant?: "regular" | "clear";
}) {
  const [internal, setInternal] = React.useState(
    defaultValue ?? items[0]?.value
  );
  const value = valueProp ?? internal;
  const refs = React.useRef(new Map<string, HTMLButtonElement>());
  const [pill, setPill] = React.useState<{ left: number; width: number }>();

  const measure = React.useCallback(() => {
    const el = refs.current.get(value);
    if (el) setPill({ left: el.offsetLeft, width: el.offsetWidth });
  }, [value]);

  React.useLayoutEffect(() => {
    measure();
  }, [measure]);

  React.useEffect(() => {
    window.addEventListener("resize", measure);
    return () => window.removeEventListener("resize", measure);
  }, [measure]);

  const select = (v: string) => {
    if (valueProp === undefined) setInternal(v);
    onValueChange?.(v);
  };

  return (
    <Glass
      variant={variant}
      data-slot="glass-tab-bar"
      role="tablist"
      className={cn("inline-flex rounded-full p-1", className)}
      {...props}
    >
      {/* Sliding glass pill */}
      {pill ? (
        <span
          aria-hidden
          data-slot="glass-tab-bar-pill"
          className="absolute top-1 bottom-1 -z-[1] rounded-full bg-white/70 shadow-[inset_0_0_0_0.5px_rgba(255,255,255,0.5),0_2px_8px_rgba(0,0,0,0.15)] transition-[left,width] duration-350 ease-[cubic-bezier(0.34,1.3,0.64,1)] dark:bg-white/20"
          style={{ left: pill.left, width: pill.width }}
        />
      ) : null}

      {items.map((item) => {
        const active = item.value === value;
        return (
          <button
            key={item.value}
            ref={(el) => {
              if (el) refs.current.set(item.value, el);
            }}
            type="button"
            role="tab"
            aria-selected={active}
            onClick={() => select(item.value)}
            className={cn(
              "flex h-11 min-w-[64px] cursor-default select-none flex-col items-center justify-center gap-0.5 rounded-full px-4 outline-none transition-colors duration-200 focus-visible:ring-[3px] focus-visible:ring-blue/40 [&_svg]:size-5 [&_svg]:shrink-0",
              active ? "text-label" : "text-label/60"
            )}
          >
            {item.icon}
            <span className="text-caption-2 font-medium">{item.label}</span>
          </button>
        );
      })}
    </Glass>
  );
}

export { GlassTabBar };

"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

/**
 * Liquid Glass (iOS 26 / macOS Tahoe) — a floating, light-bending
 * material for the CONTROL layer. Per Apple's guidance: use it for
 * elements that float above content (bars, buttons, badges), never
 * for the content itself, and avoid stacking glass on glass.
 *
 * `regular` adapts and stays legible anywhere; `clear` is more
 * transparent and belongs over media-rich backgrounds.
 */
const glassVariants = cva("relative isolate", {
  variants: {
    variant: {
      regular: "glass-regular",
      clear: "glass-clear",
    },
    interactive: {
      true: "cursor-default select-none transition-[transform,background-color] duration-200 ease-[cubic-bezier(0.34,1.56,0.64,1)] hover:bg-[color-mix(in_srgb,var(--glass-bg)_100%,rgba(255,255,255,0.12))] active:scale-[0.96] focus-visible:ring-[3px] focus-visible:ring-blue/40 outline-none",
      false: "",
    },
  },
  defaultVariants: {
    variant: "regular",
    interactive: false,
  },
});

/** Moving specular sheen, the "liquid" part. Rendered on top. */
function GlassSheen() {
  return (
    <span
      aria-hidden
      data-slot="glass-sheen"
      className="pointer-events-none absolute inset-0 -z-[1] overflow-hidden rounded-[inherit]"
    >
      <span className="absolute -inset-x-1/4 -top-3/4 h-full rotate-[-8deg] bg-[radial-gradient(50%_60%_at_50%_100%,rgba(255,255,255,0.28),transparent_70%)]" />
    </span>
  );
}

function Glass({
  className,
  variant,
  interactive,
  asChild: _ignored,
  sheen = true,
  children,
  ...props
}: React.ComponentProps<"div"> &
  VariantProps<typeof glassVariants> & {
    asChild?: never;
    /** Disable the specular sheen layer. */
    sheen?: boolean;
  }) {
  return (
    <div
      data-slot="glass"
      className={cn(glassVariants({ variant, interactive }), className)}
      {...props}
    >
      {sheen ? <GlassSheen /> : null}
      {children}
    </div>
  );
}

export { Glass, GlassSheen, glassVariants };
